local G = DYCLegendary local require = G.DYCModRequire local Spell = require( "dyc_spell" ) local DYCSpawnFX = require( "dyc_spawnfx" ) local CommonFns = require( "dyc_commonfns" ) local GetEntSize = G.GetEntSize local IsAliveOrNoHealth = CommonFns.IsAliveOrNoHealth local function GetHitSymbol(inst) return inst and inst.components.combat and inst.components.combat.hiteffectsymbol end local function Attack(spell, target, count) if not target or not target:IsValid() then return end local damage = spell.damage local caster = spell.caster local fx = count % 0x2 == 0x1 and SpawnPrefab( "dyc_fx_windblade_l" ) or SpawnPrefab( "dyc_fx_windblade_r" ) fx.Transform:SetPosition(target:GetPosition():Get()) local w, h = GetEntSize(target) local size = math.min(w, h) * 1.5 target:AddChild(fx) fx.Transform:SetPosition(0x0, h * 1.2, 0x0) fx.Transform:SetScale(size, size, size) if not IsAliveOrNoHealth(target) then return end local health = target.components.health if spell.damageType == "fire" then if target.components.burnable and not target.components.fueled then target.components.burnable:Ignite() end end if target.components.combat then target.isNonAttDmg = true target.components.combat:GetAttacked(caster, damage, spell.weapon) target.isNonAttDmg = nil end if spell.damageType == "ice" then if target.components.freezable then target.components.freezable:AddColdness(spell.coldness or 0x1) target.components.freezable:SpawnShatterFX() end if target.components.burnable then if target.components.burnable:IsBurning() then target.components.burnable:Extinguish() elseif target.components.burnable.IsSmoldering and target.components.burnable:IsSmoldering() then target.components.burnable:SmotherSmolder() end end end end local function onSetData(spell, data) data = data or {} spell.caster = data.caster spell.weapon = data.weapon spell.damage = data and data.damage or 0xa spell.interval = data and data.interval or 0.2 spell.number = data and data.number or 0x6 spell.damageType = data and data.damageType or "regular" end local function onStopTask(spell, task) end local name = "bladeofwind" local SpellClass = Class(Spell, function(self, data) Spell._ctor(self, {name = name,}) local spell = self spell.onSetData = onSetData spell.onStopTask = onStopTask spell:SetData(data) spell.onCast = function(spell, target, p) if not target then return end local timer, timerAttack, count = 0x0, 0x0, 0x0 local task = nil local frameInterval = spell.interval task = spell:StartTask(frameInterval, function() timer = timer + frameInterval spell.timer = timer timerAttack = timerAttack + frameInterval if timerAttack >= spell.interval then timerAttack = 0x0 count = count + 0x1 Attack(spell, target, count) end if count >= spell.number then spell:StopTask(task) end end) end end) SpellClass.name = name return SpellClass 